import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from '../api/axios';

export default function Profile() {
  const [reservations, setReservations] = useState([]);
  const [eligibleForReview, setEligibleForReview] = useState({});
  const [reviews, setReviews] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showReviewModal, setShowReviewModal] = useState(false);
  const [selectedReservation, setSelectedReservation] = useState(null);
  const [reviewRating, setReviewRating] = useState(5);
  const [reviewText, setReviewText] = useState('');
  const [submittingReview, setSubmittingReview] = useState(false);
  const [reviewSuccess, setReviewSuccess] = useState(false);
  const [reviewError, setReviewError] = useState('');
  const navigate = useNavigate();
  
  const username = localStorage.getItem('username');
  const email = localStorage.getItem('email');

  useEffect(() => {
    const token = localStorage.getItem('access_token');
    if (!token) {
      navigate('/login');
      return;
    }
    fetchReservations();
    fetchEligibleForReview();
  }, [navigate]);

  const fetchEligibleForReview = async () => {
    try {
      const userEmail = localStorage.getItem('email');
      if (userEmail) {
        const response = await axios.get(`/reviews/eligible/?email=${encodeURIComponent(userEmail)}`);
        const eligibleData = {};
        response.data.forEach(item => {
          eligibleData[item.id] = { eligible: !item.has_review, has_review: item.has_review };
        });
        setEligibleForReview(eligibleData);
        
        // Fetch existing reviews
        const reviewsData = {};
        for (const item of response.data) {
          if (item.has_review) {
            try {
              const reviewRes = await axios.get(`/reviews/reservation/${item.id}/`);
              reviewsData[item.id] = reviewRes.data;
            } catch (e) {
              console.log('Error fetching review:', e);
            }
          }
        }
        setReviews(reviewsData);
      }
    } catch (err) {
      console.log('Error fetching eligible for review:', err);
    }
  };

  const fetchReservations = async () => {
    try {
      // Get user info from localStorage
      const userEmail = localStorage.getItem('email');
      const userName = localStorage.getItem('username');
      
      let foundReservations = [];
      
      // Try to fetch by email first
      if (userEmail) {
        try {
          const response = await axios.get(`/user/reservations/?email=${encodeURIComponent(userEmail)}`);
          if (response.data && response.data.length > 0) {
            foundReservations = response.data;
          }
        } catch (err) {
          console.log('Email search failed:', err.message);
        }
      }

      // If no results from email, try username (matching reservation name)
      if (foundReservations.length === 0 && userName) {
        try {
          const response = await axios.get(`/user/reservations/?username=${encodeURIComponent(userName)}`);
          if (response.data && response.data.length > 0) {
            foundReservations = response.data;
          }
        } catch (err) {
          console.log('Username search failed:', err.message);
        }
      }

      // If still no results, try fetching all reservations
      if (foundReservations.length === 0) {
        try {
          const response = await axios.get('/reservations/');
          foundReservations = response.data || [];
        } catch (err) {
          console.log('All reservations fetch failed:', err.message);
          foundReservations = [];
        }
      }

      setReservations(foundReservations);
      setLoading(false);
    } catch (err) {
      console.error('Error fetching reservations:', err);
      setError('Failed to load reservations. Please try again.');
      setLoading(false);
    }
  };

  const downloadInvoice = (reservationId) => {
    const token = localStorage.getItem('access_token');
    const downloadUrl = `http://localhost:8000/api/invoices/${reservationId}/download/`;
    
    // Open invoice in new tab for download
    window.open(downloadUrl, '_blank');
  };

  const getStatusStyle = (status) => {
    switch (status.toLowerCase()) {
      case 'confirmed':
        return { background: '#d4edda', color: '#155724', padding: '4px 12px', borderRadius: '4px' };
      case 'pending':
        return { background: '#fff3cd', color: '#856404', padding: '4px 12px', borderRadius: '4px' };
      case 'cancelled':
        return { background: '#f8d7da', color: '#721c24', padding: '4px 12px', borderRadius: '4px' };
      default:
        return { background: '#e2e3e5', color: '#383d41', padding: '4px 12px', borderRadius: '4px' };
    }
  };

  const formatDate = (dateString) => {
    if (!dateString) return '-';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-IN', { 
      year: 'numeric', 
      month: 'short', 
      day: 'numeric' 
    });
  };

  const openReviewModal = (reservation) => {
    setSelectedReservation(reservation);
    setShowReviewModal(true);
    setReviewSuccess(false);
    setReviewError('');
    setReviewRating(5);
    setReviewText('');
  };

  const submitReview = async () => {
    if (!selectedReservation) return;
    
    setSubmittingReview(true);
    setReviewError('');
    
    try {
      await axios.post('/reviews/', {
        reservation: selectedReservation.id,
        rating: reviewRating,
        review_text: reviewText
      });
      
      setReviewSuccess(true);
      fetchEligibleForReview(); // Refresh to update status
      
      setTimeout(() => {
        setShowReviewModal(false);
        setReviewSuccess(false);
      }, 2000);
    } catch (err) {
      setReviewError(err.response?.data?.error || 'Failed to submit review. Please try again.');
    } finally {
      setSubmittingReview(false);
    }
  };

  const isEligibleForReview = (reservation) => {
    const today = new Date();
    const checkoutDate = new Date(reservation.check_out);
    return checkoutDate < today;
  };

  if (loading) {
    return (
      <div style={styles.container}>
        <div style={styles.loading}>Loading your reservations...</div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>My Profile</h1>
        <p style={styles.subtitle}>Welcome back, {username}!</p>
      </div>

      <div style={styles.content}>
        {error && <div style={styles.error}>{error}</div>}

        <div style={styles.section}>
          <h2 style={styles.sectionTitle}>My Reservations</h2>
          
          {reservations.length === 0 ? (
            <div style={styles.emptyState}>
              <p>You don't have any reservations yet.</p>
              <Link to="/reserve" style={styles.bookBtn}>Book Now</Link>
            </div>
          ) : (
            <div style={styles.reservationList}>
              {reservations.map((reservation) => (
                <div key={reservation.id} style={styles.reservationCard}>
                  <div style={styles.cardHeader}>
                    <div>
                      <span style={styles.bookingId}>#{reservation.id}</span>
                      <span style={getStatusStyle(reservation.status)}>{reservation.status}</span>
                    </div>
                    <button 
                      onClick={() => downloadInvoice(reservation.id)}
                      style={styles.downloadBtn}
                    >
                      📄 Download Invoice
                    </button>
                  </div>
                  
                  <div style={styles.cardBody}>
                    <div style={styles.infoGrid}>
                      <div style={styles.infoItem}>
                        <label>Check-in</label>
                        <span>{formatDate(reservation.check_in)}</span>
                      </div>
                      <div style={styles.infoItem}>
                        <label>Check-out</label>
                        <span>{formatDate(reservation.check_out)}</span>
                      </div>
                      <div style={styles.infoItem}>
                        <label>Room Type</label>
                        <span>{reservation.room_type || 'Standard'}</span>
                      </div>
                      <div style={styles.infoItem}>
                        <label>Rooms</label>
                        <span>{reservation.rooms}</span>
                      </div>
                      <div style={styles.infoItem}>
                        <label>Guests</label>
                        <span>Adults: {reservation.adults}, Children: {reservation.children}</span>
                      </div>
                      <div style={styles.infoItem}>
                        <label>Total Amount</label>
                        <span style={styles.amount}>₹{reservation.total_amount}</span>
                      </div>
                    </div>
                  </div>
                  
                  <div style={styles.cardFooter}>
                    <span style={styles.dateText}>
                      Booked on: {formatDate(reservation.created_at)}
                    </span>
                    {isEligibleForReview(reservation) && (
                      <div style={styles.reviewSection}>
                        {eligibleForReview[reservation.id]?.has_review ? (
                          <div style={styles.reviewedBadge}>
                            <span style={styles.star}>★</span> You reviewed this stay
                          </div>
                        ) : (
                          <button 
                            onClick={() => openReviewModal(reservation)}
                            style={styles.reviewBtn}
                          >
                            ⭐ Write a Review
                          </button>
                        )}
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Review Modal */}
      {showReviewModal && (
        <div style={styles.modalOverlay}>
          <div style={styles.modalContent}>
            <div style={styles.modalHeader}>
              <h2 style={styles.modalTitle}>Write a Review</h2>
              <button 
                onClick={() => setShowReviewModal(false)}
                style={styles.closeBtn}
              >
                ✕
              </button>
            </div>
            
            <div style={styles.modalBody}>
              {reviewSuccess ? (
                <div style={styles.successMessage}>
                  <span style={styles.successIcon}>✓</span>
                  <p>Thank you for your review!</p>
                </div>
              ) : (
                <>
                  <div style={styles.ratingSection}>
                    <label style={styles.ratingLabel}>Rating</label>
                    <div style={styles.starsContainer}>
                      {[1, 2, 3, 4, 5].map((star) => (
                        <button
                          key={star}
                          onClick={() => setReviewRating(star)}
                          style={{
                            ...styles.starBtn,
                            color: star <= reviewRating ? '#ffc107' : '#666'
                          }}
                        >
                          ★
                        </button>
                      ))}
                    </div>
                  </div>
                  
                  <div style={styles.textSection}>
                    <label style={styles.textLabel}>Your Review</label>
                    <textarea
                      value={reviewText}
                      onChange={(e) => setReviewText(e.target.value)}
                      placeholder="Share your experience at Eden's Glamp Resort..."
                      style={styles.textarea}
                      rows={5}
                    />
                  </div>
                  
                  {reviewError && (
                    <div style={styles.errorMessage}>{reviewError}</div>
                  )}
                  
                  <button
                    onClick={submitReview}
                    disabled={submittingReview}
                    style={styles.submitBtn}
                  >
                    {submittingReview ? 'Submitting...' : 'Submit Review'}
                  </button>
                </>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

const styles = {
  container: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #1a1a1a 0%, #2d2d2d 100%)',
    padding: '40px 20px',
  },
  header: {
    textAlign: 'center',
    marginBottom: '40px',
  },
  title: {
    color: '#c89d5c',
    fontSize: '32px',
    marginBottom: '10px',
  },
  subtitle: {
    color: '#aaa',
    fontSize: '16px',
  },
  content: {
    maxWidth: '900px',
    margin: '0 auto',
  },
  section: {
    background: 'rgba(255, 255, 255, 0.05)',
    borderRadius: '12px',
    padding: '30px',
    border: '1px solid rgba(200, 157, 92, 0.2)',
  },
  sectionTitle: {
    color: '#fff',
    fontSize: '24px',
    marginBottom: '20px',
    borderBottom: '1px solid rgba(200, 157, 92, 0.3)',
    paddingBottom: '10px',
  },
  loading: {
    textAlign: 'center',
    color: '#c89d5c',
    fontSize: '18px',
    padding: '60px',
  },
  error: {
    background: 'rgba(220, 53, 69, 0.1)',
    border: '1px solid #dc3545',
    color: '#dc3545',
    padding: '15px',
    borderRadius: '8px',
    marginBottom: '20px',
  },
  emptyState: {
    textAlign: 'center',
    padding: '40px',
    color: '#aaa',
  },
  bookBtn: {
    display: 'inline-block',
    marginTop: '15px',
    background: '#c89d5c',
    color: '#1a1a1a',
    padding: '12px 30px',
    borderRadius: '6px',
    textDecoration: 'none',
    fontWeight: '600',
  },
  reservationList: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
  },
  reservationCard: {
    background: 'rgba(255, 255, 255, 0.03)',
    borderRadius: '10px',
    border: '1px solid rgba(255, 255, 255, 0.1)',
    overflow: 'hidden',
  },
  cardHeader: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '15px 20px',
    background: 'rgba(200, 157, 92, 0.1)',
    borderBottom: '1px solid rgba(255, 255, 255, 0.05)',
  },
  bookingId: {
    color: '#c89d5c',
    fontWeight: 'bold',
    marginRight: '12px',
    fontSize: '16px',
  },
  downloadBtn: {
    background: '#c89d5c',
    color: '#1a1a1a',
    border: 'none',
    padding: '10px 20px',
    borderRadius: '6px',
    cursor: 'pointer',
    fontWeight: '600',
    fontSize: '14px',
    transition: 'all 0.2s',
  },
  cardBody: {
    padding: '20px',
  },
  infoGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
    gap: '15px',
  },
  infoItem: {
    display: 'flex',
    flexDirection: 'column',
    gap: '5px',
  },
  amount: {
    color: '#c89d5c',
    fontSize: '18px',
    fontWeight: 'bold',
  },
  cardFooter: {
    padding: '12px 20px',
    borderTop: '1px solid rgba(255, 255, 255, 0.05)',
    background: 'rgba(0, 0, 0, 0.2)',
  },
  dateText: {
    color: '#666',
    fontSize: '13px',
  },
  reviewSection: {
    display: 'flex',
    justifyContent: 'flex-end',
    alignItems: 'center',
  },
  reviewBtn: {
    background: 'linear-gradient(135deg, #c89d5c 0%, #a67c3d 100%)',
    color: '#1a1a1a',
    border: 'none',
    padding: '8px 16px',
    borderRadius: '6px',
    cursor: 'pointer',
    fontWeight: '600',
    fontSize: '13px',
    transition: 'all 0.2s',
  },
  reviewedBadge: {
    display: 'flex',
    alignItems: 'center',
    gap: '5px',
    color: '#4caf50',
    fontSize: '13px',
    fontWeight: '600',
  },
  star: {
    fontSize: '16px',
  },
  modalOverlay: {
    position: 'fixed',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    background: 'rgba(0, 0, 0, 0.7)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    zIndex: 1000,
  },
  modalContent: {
    background: '#2d2d2d',
    borderRadius: '12px',
    width: '90%',
    maxWidth: '500px',
    border: '1px solid rgba(200, 157, 92, 0.3)',
  },
  modalHeader: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '20px',
    borderBottom: '1px solid rgba(255, 255, 255, 0.1)',
  },
  modalTitle: {
    color: '#c89d5c',
    margin: 0,
    fontSize: '20px',
  },
  closeBtn: {
    background: 'transparent',
    border: 'none',
    color: '#aaa',
    fontSize: '20px',
    cursor: 'pointer',
  },
  modalBody: {
    padding: '20px',
  },
  ratingSection: {
    marginBottom: '20px',
  },
  ratingLabel: {
    display: 'block',
    color: '#fff',
    marginBottom: '10px',
    fontWeight: '600',
  },
  starsContainer: {
    display: 'flex',
    gap: '5px',
  },
  starBtn: {
    background: 'transparent',
    border: 'none',
    fontSize: '32px',
    cursor: 'pointer',
    transition: 'transform 0.2s',
  },
  textSection: {
    marginBottom: '20px',
  },
  textLabel: {
    display: 'block',
    color: '#fff',
    marginBottom: '10px',
    fontWeight: '600',
  },
  textarea: {
    width: '100%',
    padding: '12px',
    borderRadius: '8px',
    border: '1px solid rgba(255, 255, 255, 0.2)',
    background: 'rgba(255, 255, 255, 0.05)',
    color: '#fff',
    fontSize: '14px',
    resize: 'vertical',
    fontFamily: 'inherit',
  },
  submitBtn: {
    width: '100%',
    padding: '14px',
    background: 'linear-gradient(135deg, #c89d5c 0%, #a67c3d 100%)',
    color: '#1a1a1a',
    border: 'none',
    borderRadius: '8px',
    fontSize: '16px',
    fontWeight: '600',
    cursor: 'pointer',
    transition: 'all 0.2s',
  },
  successMessage: {
    textAlign: 'center',
    padding: '40px 20px',
  },
  successIcon: {
    display: 'block',
    fontSize: '48px',
    color: '#4caf50',
    marginBottom: '15px',
  },
  errorMessage: {
    background: 'rgba(220, 53, 69, 0.1)',
    border: '1px solid #dc3545',
    color: '#dc3545',
    padding: '12px',
    borderRadius: '8px',
    marginBottom: '15px',
    fontSize: '14px',
  },
};
